@startuml
title UTIL's Class Diagram

package "Twitter" {
  package "Util" {

    interface AccessModifiers {
      + value()
    }

    interface Attributes {
      + value()
    }

    interface Constructor {
      + value()
    }

    class MessageHandler {
      ~ {static} messageHandler : MessageHandler
      {field} o fadeIn : FadeTransition
      {field} o fadeOut : FadeTransition
      + {static} getMessageHandler()
      - initTransitions()
      + displayMessage()
    }

    interface Methods {
      + value()
    }

    interface Singleton {
      + value()
    }

    interface WindowSizer {
      + anchorSize()
    }

  }
}

@enduml
